// ตัวเลขไทย helper
const THAI_NUMBERS = ['๐', '๑', '๒', '๓', '๔', '๕', '๖', '๗', '๘', '๙'];
function toThaiDigits(num: string | number | undefined | null): string {
  if (num === undefined || num === null) return '';
  return num.toString().replace(/[0-9]/g, (digit) => THAI_NUMBERS[parseInt(digit)]);
}

// ฟังก์ชันดึงส่วนย่อยของวันที่ประกาศอย่างปลอดภัย ป้องกันปัญหา undefined ในโหมดฟอร์มเปล่า
function getAnnounceDatePart(announceDate: string | undefined | null, index: number): string {
  if (!announceDate || announceDate.includes('...')) {
    return '............................................';
  }
  const parts = announceDate.trim().split(/\s+/);
  return parts[index] || '............................................';
}

